static const int g_GraffitiTagCount = 144;

// Teleport to next tag (cycling iterator)
// Call this from Esp_TeleportToNextGraffiti() as fallback when ECS scan finds nothing.
static inline bool GraffitiTags_TeleportNext(bool (*TeleportFn)(float, float, float)) {
    if (g_GraffitiTagCount == 0) return false;
    TPLoc& t = g_GraffitiTags[g_graffitiIdx % g_GraffitiTagCount];
    bool ok = TeleportFn(t.x, t.y, t.z);
    g_graffitiIdx = (g_graffitiIdx + 1) % g_GraffitiTagCount;
    return ok;
}

